VALUES
  ('social-worker-moex-06410', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據我國自殺防治中心的資料，下列敘述何者正確？ 自殺死亡率隨年齡增高而降低 女性的自殺死亡率比男性高 自殺守門人計畫的防治對象是自殺未遂者 自殺防治的策略之一是對購買木炭或農藥者多加關懷與詢問', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06411', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「生活結構」（life structure）是那一位學者的理論核心？ 艾瑞克森（Erikson）    亞聶（Arnett） 魏蘭（Vaillant）    李文生（拉文森，Levinson）', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06412', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列文句中有關成語的運用，何者最不適當？ 颱風登陸後，威力大減，雖仍有一些雨量，但已是「強弩之末」，不會帶來大災害 整天躲在家裡，也不肯出去找工作，再怎麼自認為「奇貨可居」，也不見得會有 好機會從天而降 針對你面臨的問題，我幾經思索提出一點兒看法，雖是「野人獻曝」，仍希望能 給你小小的幫助 剛出生三個月的小妹妹，每次嚎啕大哭時，只要媽媽抱著搖一搖就不哭了，果然 是「坐懷不亂」啊', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06413', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列選項中的成語，何者的用法與原始的意義不同？ 言者諄諄，聽者藐藐—《詩經．大雅．抑》：「誨爾諄諄；聽我藐藐。」 今是昨非—《陶淵明集．歸去來辭》：「實迷途其未遠，覺今是而昨非。」 鉤心鬥角—杜牧《阿房宮賦》：「廊腰縵迴，簷牙高啄，各抱地勢，鉤心鬥角。」 誨人不倦—《論語．述而》：「子曰：『默而識之，學而不厭，誨人不倦，何有 於我哉？』」', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06414', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '張先生參加一場男性長輩的告別式，送那一幅題辭是正確的？ 駕返瑤池  道範長存  坤儀足式  懿德常昭', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06415', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列每副對聯都指涉中國古代某位名人，請問錯誤的選項是： 義膽忠肝，六經以來二表；託孤寄命，三代而後一人－諸葛亮 楓葉四絃秋，棖觸天涯遷謫恨；潯陽千尺水，勾留江上別離情－李白 詩史數千言，秋天一鵠先生骨；草堂三五里，春水群鷗野老心－杜甫 佛骨謫來，嶺海因而生色；鱷魚徙去，江河自此澄清－韓愈', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06416', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '詩文寫作有時會採取問答模式，藉以說明作者想法，以下選項何者屬於有問有答？ 夜來風雨聲，花落知多少（孟浩然〈春曉〉） 晚來天欲雪，能飲一杯無（白居易〈問劉十九〉） 醉臥沙場君莫笑，古來征戰幾人回（王翰〈涼州詞〉） 丞相祠堂何處尋，錦官城外柏森森（杜甫〈蜀相〉）', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06417', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '以下選項中，何者與時間易逝毫無關係？ 轉頭向戶裏，漸見愁煎迫（〈焦仲卿妻〉） 自其變者而觀之，則天地曾不能以一瞬（蘇軾〈赤壁賦〉） 從來繫日乏長繩，水去雲回恨不勝。欲就麻姑買滄海，一杯春露冷如水（李商隱 〈謁山〉） 君不見黃河之水天上來，奔流到海不復回！君不見高堂明鏡悲白髮，朝如青絲暮 成雪（李白〈將進酒〉）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06418', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列詩句，何者藉柳寄託離愁？ 一樹春風千萬枝，嫩於金色軟於絲。永豐西角荒園裏，盡日無人屬阿誰 暫憑樽酒送無憀，莫損愁眉與細腰。人世死前唯有別，春風爭擬惜長條 亂條猶未變初黃，倚得東風勢便狂。解把飛花蒙日月，不知天地有清霜 碧玉妝成一樹高，萬條垂下綠絲縧。不知細葉誰裁出，二月春風似剪刀', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06419', 'social-worker', 'social-worker-moex-103-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「用國者，得百姓之力者富，得百姓之死者彊，得百姓之譽者榮。三得者具而天下 歸之，三得者亡而天下去之。」（《荀子．王霸》）下列何者與本段引文旨意相近？ 治國當嚴於賞罰，不因愛民而躊躇 國之富者去國他遷，乃政事敗亡之兆 政治以教育為首務，百姓皆知榮辱則國強 為政而得百姓之向心，戮力百業，國乃富強', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "edc2c4452d3f", "answer_pdf_sha1": "818fc2b29011", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
